var e=[{id:`L10_1`,type:`dialog`,speaker:`SPEAR_PERSONA_NULL_NULL`,text:{KOREA:`골목으로 빠지는 녀석들은 전부 정리했어.`,JPN:`路地裏に入った奴らは全部処理したわ。`,ENG:`I took care of all the ones who were headed to the alley.`,TWN:`逃進巷子裡的傢伙們都處理好了。`},stage:{bg:`CITY_STREET_NORMAL_02`,slots:{L:null,C:{char_id:`SPEAR_PERSONA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`SPEAR_PERSONA_NULL_NULL`,text:{KOREA:`그쪽은 어때?`,JPN:`そっちはどう？`,ENG:`How about you?`,TWN:`你那邊呢？`},stage:{bg:`CITY_STREET_NORMAL_02`,slots:{L:null,C:{char_id:`SPEAR_PERSONA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`MASK_MAID_NULL_NULL`,text:{KOREA:`이쪽은 엄청나게 커다란 침식체가 튀어나왔습니다.`,JPN:`こちらはものすごく大きな侵食体が出てきました。`,ENG:`A huge C.O. just popped out over here.`,TWN:`這邊冒出了一個巨大的侵蝕體。`},stage:{bg:`CITY_STREET_NORMAL`,slots:{L:null,C:null,R:{char_id:`MASK_MAID_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L17_1`,type:`dialog`,speaker:`TONFA_MAID_NULL_NULL`,text:{KOREA:`으아아아! 이쪽으로 달려오고 있슴다!`,JPN:`うわあああ！　こっちに走ってきてるっす！`,ENG:`Ahhhh! It's running this way!`,TWN:`啊啊啊！往這邊跑來了！`},stage:{bg:`CITY_STREET_NORMAL`,slots:{L:{char_id:`TONFA_MAID_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`MASK_MAID_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L18_1`,type:`dialog`,speaker:`SPEAR_PERSONA_NULL_NULL`,text:{KOREA:`아, 알겠어! 나도 지금 도우러 갈 테니까…!`,JPN:`わ、わかった！　今私も助けに行くから……！`,ENG:`O-okay! I'll go help, so...!`,TWN:`喔，我明白了！這就去幫你……！`},stage:{bg:`CITY_STREET_NORMAL`,slots:{L:{char_id:`TONFA_MAID_NULL_NULL`,face:`UNIT_SURPRISE`},C:{char_id:`SPEAR_PERSONA_NULL_NULL`,face:`UNIT_SERIOUS`},R:{char_id:`MASK_MAID_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L21_1`,type:`dialog`,speaker:`FINLEY_CIA_NULL_NULL`,text:{KOREA:`새로 공수해 온 따끈따끈한 T3 지뢰의 화력을 시험해볼 차례군.`,JPN:`新しく手に入れたアツアツのT3地雷の火力を試す番だな。`,ENG:`It's time to test the firepower of the new T3 mines that were flown in.`,TWN:`是時候測試剛剛運過來的T3地雷的火力了。`},stage:{bg:`CITY_STREET_NORMAL`,slots:{L:null,C:{char_id:`FINLEY_CIA_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`FINLEY_CIA_NULL_NULL`,text:{KOREA:`격발 시켜!`,JPN:`撃発！`,ENG:`Detonate it!`,TWN:`引爆！`},stage:{bg:`CITY_STREET_NORMAL`,slots:{L:null,C:{char_id:`FINLEY_CIA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L29_1`,type:`dialog`,speaker:`MASK_MAID_NULL_NULL`,text:{KOREA:`침식체가 있었는데요. 없습니다.`,JPN:`侵食体がゴミのようですね。`,ENG:`It's gone, like a fart in the wind.`,TWN:`剛剛有個侵蝕體，現在沒。`},stage:{bg:`CITY_STREET_NORMAL`,slots:{L:{char_id:`TONFA_MAID_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`MASK_MAID_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L30_1`,type:`dialog`,speaker:`SPEAR_PERSONA_NULL_NULL`,text:{KOREA:`침식체 반응이 사라졌어.`,JPN:`侵食体の反応が消えたわ。`,ENG:`The C.O. signals are gone.`,TWN:`侵蝕體反應消失了。`},stage:{bg:`CITY_STREET_NORMAL`,slots:{L:{char_id:`TONFA_MAID_NULL_NULL`,face:`UNIT_SURPRISE`},C:{char_id:`SPEAR_PERSONA_NULL_NULL`,face:`UNIT_SURPRISE`},R:{char_id:`MASK_MAID_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L31_1`,type:`dialog`,speaker:`SPEAR_PERSONA_NULL_NULL`,text:{KOREA:`고작 지뢰로 저런 큰 녀석을 처리했단 말이야…?`,JPN:`地雷であんな大きな奴をやっつけたの……？`,ENG:`Those mines took care of a C.O. that big...?`,TWN:`你只用地雷就幹掉那麼大一個傢伙……？`},stage:{bg:`CITY_STREET_NORMAL`,slots:{L:{char_id:`TONFA_MAID_NULL_NULL`,face:`UNIT_SURPRISE`},C:{char_id:`SPEAR_PERSONA_NULL_NULL`,face:`UNIT_IDLE`},R:{char_id:`MASK_MAID_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L33_1`,type:`dialog`,speaker:`FINLEY_CIA_NULL_NULL`,text:{KOREA:`걱정 말라고. 우리도 카운터만 믿고 빈 손으로 온 게 아니니까.`,JPN:`心配するな。俺たちもカウンターだけに頼るつもりはない。手ぶらできたわけではないのだ。`,ENG:`Fear not. We didn't come here empty-handed, putting everything on the Counters' shoulders.`,TWN:`別擔心。我們也不是空手而來的。`},stage:{bg:`CITY_STREET_NORMAL`,slots:{L:null,C:{char_id:`FINLEY_CIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L34_1`,type:`dialog`,speaker:`FINLEY_CIA_NULL_NULL`,text:{KOREA:`문제가 있다면 꽤 비싼 신품이란 거지.`,JPN:`問題があるとすれば、結構高い新品ってとこだな。`,ENG:`The problem is that it's an expensive new product.`,TWN:`只不過它的價格有些昂貴而已。`},stage:{bg:`CITY_STREET_NORMAL`,slots:{L:null,C:{char_id:`FINLEY_CIA_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L37_1`,type:`dialog`,speaker:`FINLEY_CIA_NULL_NULL`,text:{KOREA:`음? 이터니움 실드 소진이 빠르군.`,JPN:`うん？　エタニウムシールドの消耗が激しいな。`,ENG:`Hmm? The Eternium shield is fading quickly.`,TWN:`嗯？永恆之金防護網的消耗速度很快。`},stage:{bg:`CITY_STREET_NORMAL_02`,slots:{L:null,C:{char_id:`FINLEY_CIA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}}];export{e as default};